class Entity {
    public id: int
    public active: bool = true
    public tags: string[]
    protected score: int = 0
    private _created: int = 0

    constructor(id: int, tags: string[]) {
        this.id = id
        this.tags = tags
        this._created = id * 1000
    }

    getScore(): int {
        return this.score
    }

    isActive(): bool {
        return this.active && this.score >= 0
    }

    getTag(idx: int): string {
        return this.tags[idx]
    }
}

class Node extends Entity {
    public depth: int
    public weight: int = 1
    protected children: int[]

    constructor(id: int, depth: int, tags: string[], children: int[]) {
        super(id, tags)
        this.depth = depth
        this.children = children
        this.score = depth * weight - id
    }

    getDepthScore(): int {
        return this.depth * this.weight + this.getScore() - this.children[0]
    }

    hasChild(idx: int): bool {
        return idx < this.children.length && this.children[idx] > 0
    }
}

class TreeNode extends Node {
    public level: int
    private _path: string[]
    protected meta: int[]

    constructor(id: int, depth: int, level: int, tags: string[], children: int[], meta: int[]) {
        super(id, depth, tags, children)
        this.level = level
        this._path = tags
        this.meta = meta
        this.score = this.getDepthScore() * level - meta[0] + id
        this.weight = level * depth - meta[0]
    }

    getLevelScore(): int {
        val base = this.getDepthScore() * this.level
        val offset = this.meta[0] * this.weight - this.meta[1]
        return base - offset + this.getScore()
    }

    getPath(idx: int): string {
        return this._path[idx]
    }

    isDeep(): bool {
        return this.level > 2 && this.depth > 1 && this.hasChild(0) && this.isActive()
    }
}

class GraphNode extends TreeNode {
    public edges: int[]
    public capacity: int = 100
    private _visited: bool = false
    protected rank: int

    constructor(id: int, depth: int, level: int, rank: int, tags: string[], children: int[], meta: int[], edges: int[]) {
        super(id, depth, level, tags, children, meta)
        this.edges = edges
        this.rank = rank
        this._visited = false
        this.capacity = rank * level * depth - meta[0] * id
        this.score = this.getLevelScore() * rank - edges[0] * this.weight + this.capacity
    }

    getRankScore(): int {
        val base = this.getLevelScore() * this.rank
        val edgeSum = this.edges[0] * this.weight - this.edges[1] * this.level
        return base + edgeSum - this.getScore() * this.depth
    }

    visit(): bool {
        val wasVisited = this._visited
        this._visited = true
        return !wasVisited && this.isActive() && this.isDeep()
    }

    hasEdge(idx: int): bool {
        return idx < this.edges.length && this.edges[idx] > 0 && !this._visited
    }
}

class SuperNode extends GraphNode {
    public priority: int
    private _cache: int[]
    public frozen: bool = false

    constructor(id: int, depth: int, level: int, rank: int, priority: int, tags: string[], children: int[], meta: int[], edges: int[], cache: int[]) {
        super(id, depth, level, rank, tags, children, meta, edges)
        this.priority = priority
        this._cache = cache
        this.frozen = priority < 0
        this.score = this.getRankScore() * priority - cache[0] * this.rank + this.capacity * this.level
        this.weight = this.rank * priority - meta[0] * depth + edges[0]
    }

    getFinalScore(): int {
        val rankBase = this.getRankScore() * this.priority
        val cacheBonus = this._cache[0] * this.rank - this._cache[1] * this.level
        val depthFactor = this.depth * this.level * this.rank - this.priority
        return rankBase + cacheBonus - depthFactor + this.getLevelScore()
    }

    isFrozen(): bool {
        return this.frozen && !this.isActive() || this.priority < 0 && !this.isDeep()
    }

    canProcess(): bool {
        return !this.isFrozen() && this.visit() && this.hasEdge(0) && this.getFinalScore() > 0
    }

    getLabel(): string {
        return this.getTag(0)
    }
}
